INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('2020 Innovation', '2020 Innovation Training Limited', 'https://www.2020innovation.com', 'https://www.linkedin.com/company/2020-innovation', '2020 Innovation is a UK-based accountancy support business founded in 1998. The company provides training, technical expertise, and business development services to accounting and tax professionals. It supports over 1,200 member firms with a focus on enhancing practice performance and profitability.

The services offered by 2020 Innovation include CPD training and technical resources, practice development consultancy, and digital marketing solutions such as website design and social media marketing. They also provide specialized services like file reviews and support tools tailored for accounting firms. Additionally, the company organizes community events, forums, and conferences to foster peer learning and member success.

Targeting progressive accountancy and tax professionals, 2020 Innovation operates on a membership model designed for ambitious practices looking to grow their client base and improve operations. The company''s mission is to deliver exceptional value through its comprehensive range of services, creating a supportive community for accounting firms to thrive.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/f07397d8-352a-4328-a684-6931808bfaf7.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'f07397d8-352a-4328-a684-6931808bfaf7') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('AOC Formulations', 'AOC Resins UK LTD', 'https://aocformulations.com/en-emea/home/', 'https://www.linkedin.com/company/aocformulations', 'AOC Formulations is a chemical manufacturing company based in Collierville, Tennessee. The company specializes in resins and polymer solutions that enhance product performance and optimize production processes across various industries. With a reported revenue of $675.6 million and around 706 employees, AOC Formulations is committed to partnering with customers to develop innovative products that are lighter, stronger, and more versatile.

The company operates global R&D centers equipped with advanced technology, where industry specialists work on continuous innovation to improve competitiveness. AOC Formulations produces high-quality chemical products, primarily focusing on resins for polymer applications. Their services include a comprehensive approach to new product development, helping customers increase performance and create new applications.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/a9f17ca6-8c71-4d00-b672-6c7362db0618.png', TRUE, 'Large company', NULL, NULL, FALSE, '2026-02-06T00:00:00+00:00', 'a9f17ca6-8c71-4d00-b672-6c7362db0618') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Aaban', 'Aaban Partnership Limited', 'https://www.aaban.co.uk', 'https://www.linkedin.com/company/aaban', 'Aaban Partnership Ltd offers specialist mental health services to young people. Two bespoke ten bedded sister units based in Oswaldtwistle offering assessment, stabilisation, treatment, and intervention as well as a step-down service with outreach support.Our specialist team of nurses, consultant psychiatrists, clinical psychologists, and other professions offer high-quality care and treatment for young people with complex needs.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/d6960334-db6f-4aa7-a909-b7b91781a4bd.png', TRUE, NULL, NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'd6960334-db6f-4aa7-a909-b7b91781a4bd') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Aave Labs', 'Aave Limited', 'https://aave.com', 'https://www.linkedin.com/company/aavelabs', 'Aave Labs is a prominent decentralized finance (DeFi) company founded by Stani Kulechov. It originated from ETHLend, a peer-to-peer lending platform, and rebranded to Aave in 2018. The Aave Protocol, launched in 2020, provides a decentralized lending and borrowing platform that utilizes liquidity pools. Aave Labs has expanded its offerings to include a range of products such as the GHO stablecoin, the Horizon institutional platform, and various tools under its parent company Avara.

The company has achieved significant milestones, including a peak total value locked (TVL) of $19.13 billion in October 2021 and maintaining a TVL of over $11 billion across multiple blockchains. Aave Labs emphasizes security through extensive audits and risk management practices. It has also formed partnerships with major players in the industry, enhancing its reputation and reach within the DeFi ecosystem.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/6f92701a-8abd-4892-bf83-60e9918c2893.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-12T00:00:00+00:00', '6f92701a-8abd-4892-bf83-60e9918c2893') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Academy Geomatics', 'Academy Geomatics Ltd', 'https://www.academyg.com', 'https://www.linkedin.com/company/academy-geomatics-ltd', 'Academy Geomatics Ltd is a UK-based private limited company, established on January 23, 2001. Headquartered in Gateshead, Tyne and Wear, the company specializes in precise surveying and geospatial solutions. With a team of experienced professionals, Academy Geomatics serves clients across various sectors, including construction, engineering, environmental, infrastructure, energy, water management, healthcare, and heritage.

The company offers a wide range of services, such as topographical surveys, 3D laser scanning and modeling, underground utility surveys, hydrographic and bathymetric surveys, aerial surveys using drone technology, and geospatial data analysis. Their work supports applications from land-boundary surveys to structural health assessments, focusing on safety, environmental considerations, and cost-effective results. Academy Geomatics collaborates with notable organizations like WSP, NHS, and Northumbrian Water Group on significant projects, showcasing their capability in handling complex surveying tasks.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e3cb1b7e-8342-416d-8b55-28cff35ab836.png', TRUE, 'Small company', NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'e3cb1b7e-8342-416d-8b55-28cff35ab836') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Accu', 'Accu Limited', 'https://www.accu.co.uk', 'https://www.linkedin.com/company/accucomponents', 'Accu Limited, also known as Accu or Accu Components, is a UK-based e-commerce company that specializes in precision engineering components. Founded in 2012 and headquartered in Huddersfield, West Yorkshire, Accu offers a wide range of over 500,000 to 700,000 items, including screws, fasteners, fixings, washers, bolts, and custom-engineered parts. The company serves engineers, innovators, and manufacturers across more than 125 countries.

Accu aims to be the preferred shopping destination for its customers by providing fast delivery and a user-friendly e-commerce platform. It features tools like ''Screw Build'' and ''Quick Order'' to enhance the procurement process. The company has experienced significant growth, achieving an annual turnover of £18-19.2 million and employing over 79-130 people. Accu is committed to a positive workplace culture and has established partnerships, including one with Huddersfield Town A.F.C. It continues to focus on expanding its reach in the US and internationally while maintaining a strong presence in the industrial machinery and equipment sector.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/206aa62c-cdef-45ae-972a-d0b148f8c81e.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-03-04T00:00:00+00:00', '206aa62c-cdef-45ae-972a-d0b148f8c81e') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Acta Marine', 'Acta Marine UK Limited', 'https://www.actamarine.com', 'https://www.linkedin.com/company/acta-marine', 'Acta Marine is a maritime support provider based in Rotterdam, Netherlands, operating globally in the offshore energy and coastal infrastructure sectors. Founded in 1970, the company emerged from the merger of two Dutch workboat companies in 2005. Acta Marine is family-owned and employs around 337 people, generating annual revenue of $59.8 million in 2024.

The company operates a versatile fleet of over 40 vessels, including DP Multicats, Walk-to-Work Vessels, Crew Transfer Vessels, and Multipurpose & Survey Vessels. Acta Marine primarily serves the offshore wind, coastal infrastructure, and oil & gas markets. They have a strong track record in crew transport, having safely transferred over 280,000 personnel. Acta Marine is known for its innovative walk-to-work vessel operations, which prioritize comfort and efficiency, and for utilizing advanced technology in vessel maintenance.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/319994e7-5763-4862-9c2f-439016452e1b.png', TRUE, 'Large company', NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', '319994e7-5763-4862-9c2f-439016452e1b') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Advanced Propulsion Centre UK', 'Advanced Propulsion Centre UK Ltd', 'https://www.apcuk.co.uk', 'https://www.linkedin.com/company/advanced-propulsion-centre-uk', 'The Advanced Propulsion Centre UK (APC) is a non-profit organization established in 2013 through a partnership between the UK government and the automotive industry. Based at the University of Warwick in Coventry, APC aims to accelerate the development and commercialization of low-carbon and net-zero emission propulsion technologies for vehicles. It manages a £1 billion investment fund, with equal contributions from the government and the automotive sector, to support innovative projects over a ten-year period.

APC focuses on collaborative research and development projects that industrialize low-carbon automotive technologies. It offers bi-annual funding competitions, providing grants for projects in areas such as electric machines, energy storage, and lightweight structures. The organization has committed over £880 million to more than 50 projects, creating and safeguarding thousands of jobs while significantly reducing carbon emissions. APC also provides strategic insights and support for the automotive industry, helping to drive the transition to net-zero road transport and enhance the UK’s position as a leader in sustainable automotive innovation.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c0ca55b7-ff11-4dd4-a305-b410f97c7c33.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-02-25T00:00:00+00:00', 'c0ca55b7-ff11-4dd4-a305-b410f97c7c33') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Alecto', 'Alecto Conveyancing Limited', 'https://alectolegal.com/', 'https://www.linkedin.com/company/alectolegal', 'Alecto is an AI-powered law firm built for consumers, with a mission to make the law accessible to everyone on the planet.

We believe that the quality of service offered by the legal profession is woefully inadequate. It delivers bad value for money, frustrates the people it exists to serve, and lacks basic accountability.

We believe that a law firm should:

- Speak in language people actually understand
- Equip people to make informed decisions on the issues that matter to them
- Provide an empathetic, proactive service aligned with people''s end goals — not billable hours

We''re starting with property law — the legal service you''re most likely to need, and the one most desperately in need of change.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/cd04e9d0-55c4-471c-9db2-394621a9b6d6.png', TRUE, 'Small company', NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'cd04e9d0-55c4-471c-9db2-394621a9b6d6') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Alex Begg', 'Alex Begg & Co', 'https://alex-begg.co.uk', 'https://www.linkedin.com/company/alex-begg-and-company', 'Alex Begg Group Limited is a Scottish luxury textile manufacturer established in 1866 in Paisley. The company specializes in high-end scarves, shawls, knitwear, and home furnishings, with production facilities located in Ayr and Hawick, Scotland. Originally a handloom weaving operation, Alex Begg has evolved by investing in advanced machinery and focusing on quality craftsmanship.The company produces luxury woven and knitted textiles entirely in-house, utilizing traditional techniques alongside modern technology. Its core offerings include hand-loomed cashmere and wool scarves and shawls, a range of knitwear for men and women, and luxurious home furnishings. The in-house label, Begg x Co, features contemporary collections inspired by art, nature, and Scottish heritage. Alex Begg serves prestigious luxury fashion houses and brands globally, known for its commitment to quality and sustainability.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/0e0e1222-3cfd-4d29-8748-d6380b3c35d4.png', TRUE, NULL, NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', '0e0e1222-3cfd-4d29-8748-d6380b3c35d4') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Armstrong Group', 'ADV Brightware Manufacturing Ltd', 'https://armstrong-group.uk', 'https://www.linkedin.com/company/armstrong-group-uk', 'Armstrong Group is a UK-based manufacturing company that specializes in designing and producing high-quality metal and composite parts for the automotive industry. Established under new international ownership in 2020, the company is headquartered in Coventry and operates additional facilities linked to Dumfries. With a focus on innovation and quality, Armstrong Group emphasizes investment in technology and workforce training.

The company offers a range of engineering services, including design, manufacturing, and finishing of components. Key capabilities include laser cutting, CNC machining, metal forming, welding, and composites manufacturing. Armstrong Group is committed to maintaining strong relationships with leading automotive brands, leveraging its collaboration with its U.S. sister company, Trenton Pressing, to enhance its global reach. With a dedicated workforce of around 176-197 employees, the company is on a growth trajectory, reflecting its commitment to excellence in the manufacturing sector.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/b34fabbc-6856-4e3e-9dc7-3cb32fe11562.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-03-06T00:00:00+00:00', 'b34fabbc-6856-4e3e-9dc7-3cb32fe11562') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Atitlan Asset Management', 'Atitlan Asset Management Limited', 'https://www.atitlanam.com', 'https://www.linkedin.com/company/atitlan-asset-management', 'Aspiring to be the leading provider of institutional grade crypto investment solutions

A UK based Investment Adviser. Appointed Representative of Starmark Investment Management Limited, which is authorised and regulated by the FCA 

Atitlan Asset Management aims to provide:

- Simplicity: Via a secure, liquid structure
- Attractive risk-adjusted returns: Uncorrelated to traditional and crypto markets
- Diversification: Institutional-grade portfolio and risk management', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e44fa2c9-4c75-471e-baa9-fc748684e351.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-03-04T00:00:00+00:00', 'e44fa2c9-4c75-471e-baa9-fc748684e351') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('BIGTXN', 'BIGTXN LTD', 'https://www.bigtxn.com', 'https://www.linkedin.com/company/bigtxn', 'BIGTXN is a UK-based fintech company founded in 2021, specializing in AI-driven financial intelligence and compliance monitoring for the financial services industry. The company focuses on ESG investing, sanctions analytics, and risk management, providing solutions for investors and traders. BIGTXN is recognized as the world''s first dedicated data provider for monitoring ESG investing, consolidating data from over 50 institutional investor sources and over 1,000 regulatory programs across multiple sanctions jurisdictions.

The core offering of BIGTXN is the sentinel.fi® platform, a self-service tool designed for 24/7 sanctioned securities screening and continuous post-trade monitoring. This platform provides high-quality data on investments and associated risks, featuring customizable data access, AI-powered intelligence for securities monitoring, and solutions tailored to meet compliance and risk management needs. BIGTXN primarily serves financial institutions, investors, and traders globally, helping them navigate compliance and financial crime risks effectively.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/a7cb0471-0304-4f6c-b31d-d2039b4fba8f.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', 'a7cb0471-0304-4f6c-b31d-d2039b4fba8f') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('BITZER', 'BITZER UK LTD', 'https://www.bitzer.de', 'https://www.linkedin.com/company/bitzer', 'BITZER is a German company that leads the global market in refrigeration, air conditioning, and heat pump technology. Founded in 1934 by Martin Bitzer, the company has grown from a small workshop into the world''s largest independently-owned compressor manufacturer. With over 4,500 employees across 75 locations in 40 countries, BITZER has established a strong presence worldwide, supported by significant investments in research and development.

The company specializes in refrigerant compressors, offering a range of products including hermetic and semi-hermetic reciprocating compressors, lightweight aluminum compressors for transport cooling, and high-pressure transcritical CO2 systems. BITZER also provides condensing units, pressure vessels, screw compressors, scroll compressors, and frequency inverter-equipped chillers. Their innovative solutions focus on enhancing efficiency and adapting to evolving environmental standards, making them a trusted partner in various applications across the refrigeration and air conditioning sectors.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/907417a9-2b49-4475-a681-c1c12704760f.png', TRUE, 'Very large company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '907417a9-2b49-4475-a681-c1c12704760f') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Badger Meter', 'Badger Meter UK Limited', 'https://www.badgermeter.com/en-gb/', 'https://www.linkedin.com/company/badger-meter', 'Badger Meter, Inc. is a Milwaukee-based company founded in 1905, specializing in flow measurement, water quality, and control products for water utilities, municipalities, and industrial customers worldwide. The company is known for its innovative solutions, including frost-proof water meters and advanced smart metering technologies like ORION and BEACON Advanced Metering Analytics.

Badger Meter designs and manufactures a wide range of products, including various types of water meters, valves, sensors, and smart metering technologies. Their BlueEdge™ suite offers tailored hardware and software solutions for water management and optimization. The company also provides water quality monitoring solutions through its acquisitions, enhancing its capabilities in the market.

With operations in over 100 countries, Badger Meter serves a diverse customer base, including water utilities, commercial entities, and industrial sectors. Their products support efficient resource management and sustainable water use, contributing to accurate billing and pollution control. The company has demonstrated strong financial performance, reflecting its growth and leadership in smart water solutions.', 'The company is a licensed sponsor.', 4, 1, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/448407b9-b473-4eac-b8c7-a32c82c55e32.png', TRUE, 'Very large company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '448407b9-b473-4eac-b8c7-a32c82c55e32') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Belu', 'Belu Water Limited', 'https://belu.org', 'https://www.linkedin.com/company/belu-water-ltd', 'Belu is a UK-based social enterprise and drinks company founded in 2002 and headquartered in London. The company specializes in sustainable hydration solutions, offering products such as mineral water, tonic water, flavored mixers, canned water, and water filtration systems. Belu donates 100% of its net profits to WaterAid, contributing over £6.1 million since 2011 to support global access to clean water.

Belu is committed to environmental responsibility, sourcing and bottling products exclusively within the UK to minimize its carbon footprint. The company has achieved a 72% reduction in carbon intensity since 2010 and has pioneered innovations like the UK''s first water bottle made from 50% recycled plastic. Its product range is designed for hospitality businesses, workplaces, and events, emphasizing sustainability through local production and short supply chains.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/1dbd2cb4-265a-49d9-8b49-736c92252afe.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '1dbd2cb4-265a-49d9-8b49-736c92252afe') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Beyond2050', 'Beyond 2050 Limited', 'https://www.beyond2050.co.uk', 'https://www.linkedin.com/company/beyond2050strategy', 'Beyond2050 is a political strategy and communications agency specializing in hydrogen. Founded in 2020 by Rob Dale, the agency has quickly established itself as a leader in the UK hydrogen sector. It is recognized for its expertise in political and policy insight, stakeholder engagement, campaign planning, and parliamentary monitoring. Beyond2050 has been awarded Small Consultancy of the Year in the 2024 PRCA public affairs awards.

The agency offers a wide range of services, including thought leadership, bespoke events, polling, reputation research, and hydrogen policy training. Beyond2050 collaborates with top agencies in polling, market research, public relations, social media, and events management. With a strong network across politics, civil service, and industry, the team consists of experts with extensive experience in political and communications engagement. The company has achieved growth through its reputation and client recommendations, working with some of the UK''s most innovative hydrogen organizations.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/22480d28-4974-4865-93e7-a0bbaf8efe09.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', '22480d28-4974-4865-93e7-a0bbaf8efe09') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('BlackRock', 'BlackRock Investment Management (UK) Limited', 'https://www.blackrock.com/uk', 'https://www.linkedin.com/company/blackrock', 'BlackRock is the world''s largest asset manager, overseeing approximately $12.53 trillion in assets as of mid-2025. Founded in 1988 in New York by Larry Fink and seven co-founders, the company focuses on asset and risk management services for both institutional and retail clients. BlackRock went public in 1999 and has grown significantly through strategic acquisitions, including the merger with Merrill Lynch Investment Managers and the acquisition of Barclays Global Investors.

The company offers a range of products, including iShares ETFs, mutual funds, and risk management solutions powered by its proprietary Aladdin platform. In 2024, BlackRock expanded into cryptocurrency with the launch of the iShares Bitcoin Trust and iShares Ethereum Trust, which quickly became the largest crypto ETFs globally. With a workforce of around 14,900 employees and offices in over 30 countries, BlackRock serves a diverse client base, including central banks and financial regulators.', 'The company is a licensed sponsor.', 4, 35, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e39eff9c-259d-4002-a580-162051f68aef.png', TRUE, 'Very large company', 149, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'e39eff9c-259d-4002-a580-162051f68aef') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Blackwall', 'BLACKWALL SECURITY LTD', 'https://blackwall.com/en/home', 'https://www.linkedin.com/company/blackwall-solutions', 'Blackwall is a security infrastructure company dedicated to protecting web ecosystems from malicious bots and automated threats. Founded by CEO Nik Rozenberg and CTO Denis Prochko, the company focuses on delivering advanced security solutions to small and mid-sized businesses that may not be adequately served by traditional security measures. Blackwall''s leadership team includes experienced professionals across various roles, emphasizing a commitment to innovation and adaptability.

The company''s primary product, GateKeeper, is a comprehensive security and traffic management platform designed for both on-premises and cloud hosting environments. It features intelligent bot traffic management, a web application firewall, automated SSL certificate provisioning, content caching, and advanced anti-scraping mechanisms. These tools help hosting providers enhance server efficiency, reduce operational costs, and improve customer retention. Blackwall partners with hosting service providers, managed service providers, and eCommerce platforms to integrate its solutions seamlessly, making enterprise-grade security accessible to a wide range of clients.', 'The company is a licensed sponsor.', 4, 2, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/687870a0-00f9-4485-9f24-25752884c07e.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-03-05T00:00:00+00:00', '687870a0-00f9-4485-9f24-25752884c07e') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Blenheim Martlet', 'Blenheim Global Ltd', 'https://www.blenheimmartlet.com', 'https://www.linkedin.com/company/blenheim-martlet', 'Blenheim Martlet tackles complex and sensitive challenges for which communications, influence, and access are decisive.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/57a29086-3089-43fa-af6b-717e0ed2aaa1.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', '57a29086-3089-43fa-af6b-717e0ed2aaa1') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Blooming Haus', 'Blooming Haus Ltd', 'https://bloominghaus.com', 'https://www.linkedin.com/company/blooming-haus', 'Blooming Haus is Europe''s only B Corp and Planet Mark certified luxury floral and events studio, leading a new era of floristry that unites high art, conscious living, and exceptional craftsmanship. Founded in 2014 by visionary duo Michal Kowalski, a Swiss-trained Master Florist, and Michael Dariane, whose background bridges agriculture and environmental science, Blooming Haus has evolved from a Chelsea pop-up into a globally recognised creative force.

We offer a full spectrum of services including event florals, weddings, contract flowers, seasonal installations, and UK deliveries. Our work is rooted in sustainability and driven by purpose. Every design reflects a commitment to environmental stewardship, ethical sourcing, and closed-loop systems. We work exclusively with growers who uphold fair-wage practices and biodiversity, while eliminating harmful materials like floral foam in favour of reusable and biodegradable alternatives.

Our multidisciplinary approach blends floristry, fashion, horticulture, engineering, and sustainability to craft sculptural floral narratives that speak to emotion, identity, and meaning. We do not treat flowers as mere decoration. They are a language we use to create immersive, transformative experiences that leave lasting impressions on both people and the planet.

We are proud to have collaborated with leading global names such as Dior, Cartier, Burberry, Erdem, Raffles, and British Vogue. From intimate weddings and large-scale events to contract flowers for iconic spaces and editorial campaigns, our work celebrates seasonal nuance, couture-level detail, and bold creative direction.

At Blooming Haus, we create floral signatures that elevate spaces and shape brand identity. We believe floristry has the power to captivate, connect, and contribute to a more beautiful and sustainable world.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/fecf34d8-2107-414c-bd6c-319f7c130536.png', TRUE, 'Very small company', NULL, NULL, TRUE, '2026-03-11T00:00:00+00:00', 'fecf34d8-2107-414c-bd6c-319f7c130536') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Brandon Schubert', 'Brandon Schubert Ltd', 'http://www.brandonschubert.com', 'https://www.linkedin.com/company/brandon-schubert-ltd', 'Brandon Schubert - Interior Design', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/9ba5daae-ee48-4b06-8dd2-98e2debfde6b.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-24T00:00:00+00:00', '9ba5daae-ee48-4b06-8dd2-98e2debfde6b') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Breadwinners', 'Breadwinners Foundation', 'https://www.breadwinners.org.uk/', 'https://www.linkedin.com/company/breadwinners-foundation', 'Breadwinners is a not-for-profit social enterprise and registered charity founded in 2016. It sells artisan organic bread and pastries at markets while providing employability training, paid work, and mentoring to young refugees and asylum seekers in London and Brighton. The organization began as an idea from Marika Wilkinson and John Lister, evolving from bike deliveries to market stalls, and now operates 11-18 market stalls, employing about 30 refugees annually.

The charity offers a range of artisan products, including sourdoughs and pastries, sold at farmers'' markets and through wholesale to various businesses like coffee shops and restaurants. Breadwinners runs three employability programs: the Risers Programme for asylum seekers, the flagship Breadwinners Programme for those with work rights, and the Proofers Programme for online sales training. These initiatives have significantly improved participants'' well-being and employability, supporting over 360 individuals since its inception.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e16a42e3-f89b-4d19-ac25-9eeb995077fc.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-12T00:00:00+00:00', 'e16a42e3-f89b-4d19-ac25-9eeb995077fc') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('BrowserStack', 'BrowserStack UK Ltd', 'https://www.browserstack.com', 'https://www.linkedin.com/company/browserstack', 'BrowserStack is a cloud-based SaaS platform founded in 2011 and headquartered in Mumbai, India, with additional offices in San Francisco and Dublin. The company specializes in cross-browser and real-device testing for websites and mobile applications, ensuring compatibility across various browsers, devices, and operating systems. It has grown significantly, serving over 50,000 customers, including 1.5 million developers across more than 135 countries.

The platform offers a range of services, including real-time cross-browser testing, access to over 3,000 real mobile devices for testing, and automated testing capabilities with integrations like Selenium. BrowserStack also provides tools for test management and optimization, along with a freemium model that allows users to access limited testing for free. The company focuses on delivering quality and bug-free software at speed, making it a trusted choice for major enterprises such as Microsoft, Amazon, Spotify, and Twitter.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/7df0f9ed-79ed-4316-8137-a428e79dbee4.png', TRUE, 'Very large company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '7df0f9ed-79ed-4316-8137-a428e79dbee4') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Building Energy Experts', 'Building Energy Experts Limited', 'https://buildingenergyexperts.co.uk', 'https://www.linkedin.com/company/buildingenergyexperts', 'Building Energy Experts is a sustainability consulting, testing, and certification company based in Bristol, operating nationally across the UK. Incorporated in August 2016, the company focuses on enhancing building energy performance throughout its lifecycle, from planning and design to construction and existing properties.

Their services include energy modeling, sustainability statement development, as-built testing, and energy efficiency implementation. They also provide support for Part O compliance and dynamic thermal modeling. The team consists of sustainability consultants and hands-on testing specialists, ensuring effective solutions that bridge the gap between design and actual performance.

Building Energy Experts has received recognition as the Supply Chain Partner of the Year at the Unlock Net Zero Awards for their strong partnerships and innovative outcomes. They have collaborated with notable clients, including Redrow Homes, to deliver specialized energy compliance and modeling services. The company currently employs 13 people and has shown significant growth in its workforce.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e297df99-a1bc-4cac-9519-cbec46c8bbef.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', 'e297df99-a1bc-4cac-9519-cbec46c8bbef') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('CMT Group (Global)', 'CMT Equipment Ltd', 'https://cmtgroup.global', 'https://www.linkedin.com/company/cmt-group-global', 'We''re a global group, sourcing a vast range of products for both private, and public sector clients. Through extensive knowledge of every aspect of procurement, we can help you maximise efficiency, lower costs, and broaden your supply chain across the globe.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c179eabc-26e4-49cf-81e1-0cec65a1ba16.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', 'c179eabc-26e4-49cf-81e1-0cec65a1ba16') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('COROS', 'COROS WEARABLES UK LTD', 'https://uk.coros.com', 'https://www.linkedin.com/company/coroswearables', 'COROS is a performance sports technology company that designs and manufactures premium GPS sport watches and athletic wearables tailored for endurance athletes, runners, cyclists, and outdoor adventurers. Founded in 2016 and headquartered in the United States, COROS combines high-grade hardware with innovative software to create tools that enhance athletic training.

The company is recognized for its advanced GPS technologies, which provide precise tracking of routes, distances, and speeds. COROS watches feature industry-leading capabilities such as heart rate monitoring, sleep tracking, and comprehensive training analytics. Their product line includes various GPS watches, bike computers, and heart rate monitors, catering to a wide range of athletes from professional competitors to outdoor enthusiasts.

COROS emphasizes durability and long battery life, ensuring their products perform well in extreme conditions. The company collaborates with top athletes to refine its offerings and operates a connected training ecosystem through the COROS app, which supports workout planning and training guidance.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/bf8ab039-67b8-4421-831c-e9618a816e4f.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-03-06T00:00:00+00:00', 'bf8ab039-67b8-4421-831c-e9618a816e4f') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Cairn Technology', 'Cairn technology Ltd', 'https://cairntechnology.com', 'https://www.linkedin.com/company/cairn-technology-ltd', 'Cairn Technology is a health and safety specialist in the medical sector, providing a range of workplace monitoring and consultancy services to hospitals across the UK. In addition, Cairn specializes in supplying high quality surgical instruments for general and specialist surgery, as well as a portfolio of healthcare consumables such as absorbent mats, oxygen masks and incontinence products.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/f26d3611-6aa0-4292-8c23-8f15c518eb09.png', TRUE, NULL, NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', 'f26d3611-6aa0-4292-8c23-8f15c518eb09') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Capri Sun Group', 'Capri- Sun UK LTD', 'https://www.capri-sun.com/en-gb/', 'https://www.linkedin.com/company/capri-sun-group', 'Capri Sun Group, based in Switzerland, is the owner of the Capri-Sun brand, known for its juice concentrate-based drinks. Launched in 1969, Capri-Sun has become a leading kids'' drink brand, selling over 6 billion pouches annually in more than 100 countries. The company emphasizes natural fruit flavors and innovative packaging, primarily using stand-up pouches.

Founded by Rudolf Wild in 1931, Capri Sun Group has a rich history of beverage innovation. The brand gained popularity with its flexible pouch design, which was a significant departure from traditional bottles. Over the years, Capri Sun has expanded its product line to include sparkling drinks and vitamin-rich dilutables. The company operates through regional licensees, partnering with major companies like Kraft in North America and Coca-Cola Europacific Partners in Europe.', 'The company is a licensed sponsor.', 4, 1, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/559043a8-a69c-452e-bc86-976158f7d32e.png', TRUE, 'Large company', NULL, NULL, FALSE, '2026-03-04T00:00:00+00:00', '559043a8-a69c-452e-bc86-976158f7d32e') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Capsa AI', 'Capsa.AI Ltd', 'https://capsa.ai', 'https://www.linkedin.com/company/capsa-ai', 'Capsa AI is a London-based AI software company founded in 2023. It specializes in an AI operating system tailored for private equity professionals, aiming to enhance due diligence processes, unlock insights, and optimize workflows. The company operates as a seed-stage startup with a small team and is headquartered in London, with additional locations in Mile End and Kingston Vale.

Capsa AI offers CAPS A.I., a platform that aggregates data from various sources, including CRM systems and third-party platforms, to create a unified source of truth. Key features include custom workflows designed for specific fund operations, industry-specific data integration for improved market intelligence, and automation of repetitive due diligence tasks. The platform is designed to help private equity funds manage their operations more efficiently, enabling them to identify opportunities quickly and make informed decisions. Capsa AI targets the multi-trillion-pound private equity industry, serving funds with over £30 billion in assets under management.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c4a2a328-8058-4f1c-b95a-f27887b39bdd.png', TRUE, 'Small company', NULL, NULL, FALSE, '2026-03-04T00:00:00+00:00', 'c4a2a328-8058-4f1c-b95a-f27887b39bdd') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Chipotle Mexican Grill', 'EMEA Tortilla Limited', 'https://www.chipotle.co.uk', 'https://www.linkedin.com/company/chipotle-mexican-grill-uk-limited', 'CHIPOTLE MEXICAN GRILL UK LIMITED is a restaurants company based out of ELIZABETH HOUSE 13- 19 QUEEN STREET, LEEDS, United Kingdom.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/9a2e0dd5-39df-4e40-ab17-7ee7f085c881.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '9a2e0dd5-39df-4e40-ab17-7ee7f085c881') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Christofferson Robb & Company', 'CHRISTOFFERSON, ROBB & COMPANY LTD', 'https://christoffersonrobb.com', 'https://www.linkedin.com/company/christofferson-robb-&-company', 'Christofferson, Robb & Company (CRC) is an investment management firm founded in 2002 by Johan Christofferson and Richard Robb. With offices in New York and London, CRC operates in the investment management and financial advisory industry, focusing on Risk Sharing Transactions (RSTs). These transactions help transfer credit risk from banks to institutional investors, allowing banks to enhance their Core Tier 1 capital ratios and reduce the costs associated with new loans.

The firm specializes in managing investment funds that acquire credit risk from banks'' core clients, particularly in small and medium-sized enterprise (SME) loans, prime residential mortgages, and counterparty exposure management. CRC holds an estimated 35% market share in the RST sector and manages approximately $1.5 billion in net assets. The company has successfully executed large transactions across various European countries, supporting banks in managing their loan portfolios and promoting lending growth in the region.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/7cf5c41f-d9c8-4dd3-8f95-914c7605ab9d.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '7cf5c41f-d9c8-4dd3-8f95-914c7605ab9d') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Claren AI', 'WILSONAI (UK) LIMITED', 'https://www.claren.law', 'https://www.linkedin.com/company/wilsonai-company', 'Claren AI is an AI-powered legal operations platform that automates routine legal tasks for in-house legal teams and corporate counsel. Its core product, Claren, streamlines processes such as contract redlining, key term extraction, legal question answering, and multi-document workflows. By leveraging AI, Claren enables teams to save over 80% of the time spent on common tasks like contract reviews and due diligence.The platform emphasizes ethical AI use, security, and compliance, and it is adaptable across various formats and jurisdictions. Claren''s features include AI-enhanced contract redlining, automated playbook generation, and the ability to process large sets of documents with high accuracy. The company has received positive feedback from clients, who highlight its efficiency and the significant time savings it provides. Claren AI raised $1.7 million in a Pre-Seed funding round and is backed by Entrepreneurs First.', 'The company is a licensed sponsor.', 4, 1, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/94b64da6-e066-4841-bd4e-e75c7b5c0491.png', TRUE, NULL, NULL, NULL, FALSE, '2026-03-06T00:00:00+00:00', '94b64da6-e066-4841-bd4e-e75c7b5c0491') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('ControlAI', 'SECURE FUTURE RESEARCH LTD', 'https://controlai.com', 'https://www.linkedin.com/company/controlai', 'ControlAI is a non-profit organization focused on AI safety advocacy. It aims to mitigate existential risks associated with advanced AI systems, including artificial superintelligence. The organization engages in public campaigns, policy proposals, and civic engagement initiatives to raise awareness about AI risks and promote regulatory measures.ControlAI publishes newsletters, articles, and updates on various AI-related topics, including recursive self-improvement and misalignment issues. It promotes the "Direct Institutional Plan (DIP)" to encourage individuals and organizations to advocate for binding regulations on powerful AI systems. The organization has garnered support from numerous politicians and experts, emphasizing the importance of addressing potential extinction risks.Through its campaigns, ControlAI seeks to establish global "red lines" on AI development, including bans on superintelligence. It also provides educational content, including a weekly newsletter and a podcast featuring discussions on AI security and alignment. The organization collaborates on policy initiatives and shares media updates to inform the public about developments in the AI landscape.', 'The company is a licensed sponsor.', 4, 1, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/1de61268-bfa4-41ba-aff9-8079607d5b89.png', TRUE, NULL, 1, NULL, FALSE, NULL, '1de61268-bfa4-41ba-aff9-8079607d5b89') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Copenhagen Infrastructure Partners (CIP)', 'CIP FS UK LTD.', 'https://www.cip.com/', 'https://www.linkedin.com/company/copenhagen-infrastructure-partners-k-s', 'Copenhagen Infrastructure Partners (CIP) is a Danish investment firm established in 2012, focusing on large-scale greenfield energy infrastructure projects. As one of the largest dedicated renewable energy investment firms globally, CIP manages eleven funds with around €32 billion in capital raised from over 180 institutional investors. The company operates with a workforce of more than 500 employees across 19 offices worldwide, including major cities like Copenhagen, London, and New York.CIP specializes in greenfield energy infrastructure investments, entering projects early to secure exclusive opportunities and enhance risk-adjusted returns for its investors. The firm has a significant portfolio of approximately 120 GW of green energy projects, spanning offshore and onshore wind, solar photovoltaic, biomass, and energy-from-waste. Notably, CIP is recognized as a leader in offshore wind development and is advancing the commercialization of floating offshore wind technologies. The company aims to raise €100 billion by 2030 to further its green energy investments.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/79ff3a99-6770-4e6c-a2f3-2a6956aa4e55.png', TRUE, NULL, NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '79ff3a99-6770-4e6c-a2f3-2a6956aa4e55') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Covasant', 'Covasant Technologies (UK) Private Limited', 'https://www.covasant.com', 'https://www.linkedin.com/company/covasant', 'Covasant Technologies is a Texas-based company founded in 2024 through the merger of three firms. It specializes in Agentic AI-driven enterprise solutions focused on risk management, compliance, cybersecurity, and operational efficiency across various industries, including healthcare, banking, manufacturing, media, and transportation.

Headquartered in Plano, Covasant offers its core platform, Covasant AI Fabric, which integrates Agentic AI, predictive analytics, and intelligent automation. This low-code system enables autonomous AI agents to enhance decision-making and accelerate application development. The company promotes ethical AI and innovation, supported by a strong leadership team and a collaborative culture. Covasant provides a range of services, including enterprise risk management, AI engineering, data analytics, and digital transformation, tailored to meet the specific needs of its clients in different sectors.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e862e00a-fb08-4d74-8fe5-fd21c00b8a5d.png', TRUE, 'Large company', NULL, NULL, FALSE, '2026-02-26T00:00:00+00:00', 'e862e00a-fb08-4d74-8fe5-fd21c00b8a5d') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Crescent Print', 'Crescent Print Ltd', 'https://crescentprint.co.uk', 'https://www.linkedin.com/company/crescent-print-shop', 'Edinburgh Printing Service for all your urgent, high-quality print requirements. Guaranteed on-time fast turnaround. Experienced & trusted Edinburgh print shop.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/ab0634fc-ba3e-4631-9ecf-6844de9e2bcb.png', TRUE, NULL, NULL, NULL, TRUE, '2026-03-10T00:00:00+00:00', 'ab0634fc-ba3e-4631-9ecf-6844de9e2bcb') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Daisy', 'Daisy Communications Ltd', 'http://www.daisygroup.co.uk', 'https://www.linkedin.com/company/daisygroup/ ', 'Daisy Group is the UK''s largest independent provider of integrated IT, communications, and cloud services. Founded in 2001 and headquartered in Brierfield, Lancashire, the company serves approximately 185,000 businesses across the UK. Initially focused on telephone services for small and medium-sized businesses, Daisy Group has expanded its offerings through organic growth and strategic acquisitions.

The company provides a wide range of services, including communications and connectivity solutions, managed IT services, cloud migration, and cyber security. Its core offerings cater to various sectors, including public services, finance, healthcare, and retail. Daisy Group emphasizes operational resilience and business continuity, supported by a strong customer service team based in the UK. With a workforce of over 1,000 employees and a commitment to delivering technology-led solutions, Daisy Group continues to strengthen its position in the business communications and IT landscape.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/8b390436-c2db-4c79-9792-8ae4fe9d3fcb.png', TRUE, 'Very large company', NULL, NULL, FALSE, '2025-12-05T00:00:00+00:00', '8b390436-c2db-4c79-9792-8ae4fe9d3fcb') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Decant Group', 'Decant Group Limited', 'https://decantgroup.com', 'https://www.linkedin.com/company/decantgroup', 'Decant Group is a UK-based company that specializes in wine and spirits collectables. Founded in December 2019, it operates through several interconnected "Houses" that provide tailored services in investment, consumption, and production of fine wines, premium spirits, whisky casks, and bottles. The company has achieved significant growth, generating over £100 million in sales and managing £100 million in assets while serving more than 50,000 users.

The group''s specialized units include Decant Index, a digital marketplace for buying and selling fine wines and spirits; House of Decant, an online retailer with curated selections; Whisky Partners, which focuses on whisky cask sales; Decant Bond, offering secure bonded storage; and Decant Ventures, which invests in fast-growing SMEs and creates new brands. Decant Group emphasizes accessibility in alternative investments, utilizing advanced technology and client advisory services to enhance user experience and demystify the market.', 'The company is a licensed sponsor.', 4, 2, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/4d710cfd-067f-4aa8-89d0-8994e3b408dc.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', '4d710cfd-067f-4aa8-89d0-8994e3b408dc') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('DeepL', 'DeepL UK Limited', 'https://www.deepl.com/', 'https://www.linkedin.com/company/deepl', 'DeepL is an AI company based in Cologne, Germany, specializing in high-precision neural machine translation and language solutions. Founded in 2009 as Linguee, the company launched its flagship product, DeepL Translator, in 2017. Led by CEO Jaroslaw Kutylowski, DeepL utilizes proprietary neural networks trained on extensive bilingual datasets to deliver translations that are recognized for their accuracy and context-awareness.

DeepL offers several key products, including the DeepL Translator, which supports multiple languages and is known for its natural translation results. The company also provides DeepL Pro, an enterprise subscription service that integrates translation tools into business workflows, and DeepL Agent, an AI assistant designed to automate language-related tasks. With over 200,000 business customers, including many Fortune 500 companies, DeepL is positioned to make a significant impact in the AI translation and writing assistance markets.', 'The company is a licensed sponsor.', 4, 4, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/375dfe69-4cae-4d61-9df1-203c7cf82ca2.png', TRUE, 'Very large company', 7, NULL, FALSE, NULL, '375dfe69-4cae-4d61-9df1-203c7cf82ca2') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Differentiated', 'Differentiated Ltd', 'https://differentiated.co.uk', 'https://www.linkedin.com/company/differentiated', 'We believe that more ‘sales and marketing minds'' within your business will create more pipeline, close more deals, and make your customer base grow. That''s what we create. 

We also think that injecting creativity into every message you deliver is what separates you from the rest of the pack. We sit comfortably between marketing and sales in the knowledge that their combined methodologies generate exponential value.

We work via a consultancy model comprised of experienced people, and we spend more time with you than via a traditional agency model. It''s an approach that ensures we obtain a deep understanding of your business, your people, your customers and your culture.

From the development of your sales messages, through to each way you communicate them to your audience, we apply best-practice communication techniques that differentiate you to win. 

We empower the sales community to do more for the benefit of selling, and free the marketing team to invest in specific initiatives for bigger impact.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/ecd6bb67-5285-4f90-bbf2-fa87a215a9cf.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-12T00:00:00+00:00', 'ecd6bb67-5285-4f90-bbf2-fa87a215a9cf') ON CONFLICT DO NOTHING;
