INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Innvotec', 'INNVOTEC LIMITED', 'https://innvotec.com', 'https://www.linkedin.com/company/innvotec', 'Innvotec is a boutique AIFM (Alternative Investment Fund Manager) holding an extensive suite of Regulatory Permissions. We are proud to be one of the UK''s longest established independent Fund Managers and have been fully regulated since our inception. We have no constraint on the type of Fund we can raise and manage.
 
Historically, our focus has been, and continues to be, private equity and capital appreciation whilst also considering the social, economic and environmental impact of our investments.
 
From its formation, Innvotec has always concentrated on investing in private companies at the earlier stages of development. This is where we believe there is the greatest opportunity for growth and capital appreciation. We specialise in markets where our team members and advisors have experience as investors and entrepreneurs.
 
Innvotec raises both limited partnerships for large and institutional investors and tax-efficient funds for UK private investors. Our range of funds has recently been expanded to offer all investors the opportunity of investing on a global basis.
 
We are actively building our portfolio of companies, many of which are developing technologies and propositions that can disrupt industries and solve the most challenging problems the world faces today. Innvotec looks for companies that have the potential to transform the very industry in which they operate. We believe in helping to turn great entrepreneurs and their companies into global winners. Innvotec''s focus is on finding and supporting bold and ambitious founders who have the ambition and determination to build global success stories.
 
Successful growth for innovative companies requires an ecosystem of expertise and support. This is what the Innvotec team provides to the entrepreneurs and their companies throughout the different stages of their development and growth. Innvotec can unlock opportunities to connect with relevant corporates or afford introductions to leading industry expertise.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/d453d8a9-5380-44a1-be01-188e80462957.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-10T00:00:00+00:00', 'd453d8a9-5380-44a1-be01-188e80462957') ON CONFLICT DO NOTHING;
