INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Kohtari', 'Kohtari Limited', 'https://kohtari.ai', 'https://www.linkedin.com/company/kohtari', 'We''re a water intelligence company, bringing digital visibility to our planet''s most precious resource.

By combining drones, AI, and Data, we reveal previously invisible water insights. From real-time monitoring to prediction and management. Our solutions turn complex data into actionable intelligence. We help water companies make faster, smarter decisions that protect both water and reputation.

Our vision is a world where every significant water body is digitally visible, understood and protected — ensuring resilient ecosystems, healthier communities and a thriving blue economy.

Backed by a £7m Ofwat-funded project and building on Kohtari''s heritage in AI and data, we''re advancing two breakthrough capabilities:

• Coastal water quality monitoring: delivering real-time insights at scale.
• Prediction and management: next-generation AI models enhanced by the reach and precision of drone technology.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/68871c3a-781b-4341-b463-d2b862642d05.png', TRUE, 'Small company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '68871c3a-781b-4341-b463-d2b862642d05') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Labaton Keller Sucharow LLP', 'Labaton Keller Sucharow UK Limited', 'https://www.labaton.com', 'https://www.linkedin.com/company/labaton-keller-sucharow-llp', 'Labaton Keller Sucharow LLP is a leading American plaintiffs'' law firm established in 1963, with a focus on complex litigation for investors and consumers. The firm operates from offices in New York, Delaware, Washington, D.C., and London, employing 75 lawyers and 26 partners. Since the enactment of the Private Securities Litigation Reform Act in 1995, it has successfully recovered over $27 billion for clients, representing more than 300 institutional investors managing over $4.5 trillion in assets.

The firm specializes in four main areas: securities litigation, corporate governance and shareholder rights litigation, consumer protection and data privacy litigation, and alternative dispute resolution. Notable achievements include significant settlements for shareholders of Dell Technologies, Discovery Inc., and Walmart, among others. Labaton Keller Sucharow is recognized for its tenacious advocacy against corporate wrongdoing and offers global securities portfolio monitoring and advisory services, along with comprehensive case evaluations. The firm is committed to serving large institutional investors worldwide, ensuring robust representation in high-stakes legal matters.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/a5d724d8-680f-4b20-b7bc-0ec80cba4300.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-02-27T00:00:00+00:00', 'a5d724d8-680f-4b20-b7bc-0ec80cba4300') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Lemonaid & ChariTea UK', 'Lemonaid Beverages Ltd', 'https://drinkinghelps.co.uk', 'https://www.linkedin.com/company/lemonaid-charitea-uk', 'Squeezed from fresh fruits without squeezing our growers, Lemonaid and ChariTea are soft drinks how they should be. Made from Organic and Fairtrade certified ingredients. As a Social Enterprise we deliberately pay higher prices for the raw ingredients to promote fair and sustainable trading conditions. By supporting Fairtrade, farmers and workers are empowered to combat poverty and take more control over their lives.

But we don''t just rely on international certificates and quality seals. We want to see for ourselves exactly where the ingredients come from. That''s why every year, we travel to the farming regions to get to know the local farmers.

What''s more, for every bottle sold, 5p go to the Lemonaid & ChariTea Foundation which supports people and communities to help themselves, with over £7 million raised to date. Focusing on parts of the world frequently disadvantaged in the global economy, the Foundation supports local initiatives which work to improve social, economic and ecological structures.

That''s how #drinkinghelps.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/51fdc57b-57e9-4f0d-8188-bf6bbe10fe22.png', TRUE, 'Very small company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '51fdc57b-57e9-4f0d-8188-bf6bbe10fe22') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Leonardo', 'LEONARDO BELGIUM SA', 'https://www.leonardo.com/en/home', 'https://www.linkedin.com/company/leonardo_company', 'Leonardo S.p.A. is a global high-technology company focused on Aerospace, Defence, and Security. Established in 1948 as Finmeccanica, it rebranded to Leonardo in 2017 to honor the legacy of Leonardo da Vinci. The company employs over 60,000 people across 129 sites worldwide, with a strong presence in Italy, the UK, Poland, and the USA. Leonardo is listed on the Borsa Italiana and is part of the FTSE MIB and Dow Jones Sustainability Indices.

The company operates through five main divisions: Helicopters, Defence Electronics, Aeronautics, Space, and Cyber & Security Solutions. Leonardo develops and integrates systems for air and sea traffic management, border control, secure communications, IT infrastructure, and aerospace technologies. Its expertise includes shipbuilding, electronics, mechanics, and artificial intelligence, reflecting a commitment to innovation and systemic thinking inspired by its namesake.', 'The company is a licensed sponsor.', 4, 300, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/e789ca69-f3bb-4fe4-9667-1aa379d4201c.png', TRUE, 'Very large company', NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', 'e789ca69-f3bb-4fe4-9667-1aa379d4201c') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Lindus', 'Lindus Health Limited', 'https://www.lindushealth.com/', 'https://www.linkedin.com/company/lindushealth/', 'Lindus Health is a UK-based company founded in 2021 that specializes in delivering end-to-end clinical trials for the life sciences sector, including biotechnology and pharmaceutical companies. Headquartered in London, Lindus Health utilizes its proprietary technology platform, Citrus™, to enhance efficiency and data quality in clinical research. The company has raised over $80 million in funding and has conducted 42 clinical trials across North America, the UK, and Europe, enrolling over 36,000 patients in various health areas.

Lindus Health offers a comprehensive All-in-One CRO solution that covers the entire clinical trial lifecycle. Their services include study design, patient recruitment, clinical data management, and project management, all aimed at streamlining the trial process. The Citrus™ platform integrates AI and automation to support various aspects of clinical trials, including remote data capture and regulatory compliance. Lindus Health emphasizes patient-centric research and has established partnerships with notable life science organizations to enhance its offerings.', 'Sponsorship can be offered for all roles.', 1, 7, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/8.png', TRUE, 'Medium-sized company', 1, 7, FALSE, '2022-02-17T00:00:00+00:00', '8') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('London Cosmetic Clinic', 'LONDON KNIGHTSBRIDGE COSMETIC CLINIC LIMITED', 'https://www.thelondoncosmeticclinic.co.uk/', 'https://www.linkedin.com/company/london-cosmetic-clinic', 'Expert non-surgical cosmetic treatments in Harley Street, London. Botox, fillers and skin rejuvenation by trusted aesthetic doctors.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c3d55a37-0acd-4280-902a-d1fc720f96ff.png', TRUE, 'Very small company', NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', 'c3d55a37-0acd-4280-902a-d1fc720f96ff') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Love Supreme Projects', 'A Love Supreme (Operations) Limited', 'https://lovesupremeprojects.com/', 'https://www.linkedin.com/company/lovesupremeprojects', 'Practise yoga, meditate, chant and so much more with us.

We opened our doors in February of 2022, on the tail end of a global pandemic. Our need to be together, the inequality of our world and the eternal truth that love is the glue that binds us together came into clear focus. This magical practice that is Yoga (from asana, to chanting, to breathing, to meditating) and the tools it provides to deal with life''s inevitable ups and downs were needed more than ever, and we wanted to give people from all backgrounds access to them. Oh, and we knew we had to turn to joy whilst doing it all! 

We come together to take care of our bodies, quieten our minds and, most importantly, tend our hearts. We dance and listen to live sound and music on Friday Nights and give back to our local & global community with the Sunday Specials, all while drinking chai and eating samosas & cookies. 
 Whether you are near us on Golborne Road in Notting Hill or in some far-off corner of the globe (everything is on Zoom), come and practise with us and Crack Your Heart Open.

The Love Supreme Projects Team ❤️', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/60ee0c9c-e42f-4f19-bfd8-8ce7ca00aa60.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', '60ee0c9c-e42f-4f19-bfd8-8ce7ca00aa60') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Luxion', 'Luxion Group Limited', 'https://www.luxion.group', 'https://www.linkedin.com/company/luxiongroup', 'Luxion is a software company founded in 2003, headquartered in Tustin, California, with additional offices in Denmark. The company specializes in advanced 3D visualization, rendering, animation, and lighting technology. Luxion develops innovative solutions for computer-based lighting simulations, focusing on daylighting, material light scattering, and real-time rendering. It operates as Luxion Group ApS and has a diverse customer base, including over 60% of Fortune 500 companies.

The company''s main products include KeyShot, a leading 3D rendering and animation software that allows users to create photorealistic visualizations and interactive product displays, and KeyVR, which facilitates collaborative virtual reality experiences for design reviews. Luxion has also enhanced its offerings through the acquisition of Digizuite A/S, integrating digital asset management solutions to streamline content delivery and automate workflows. Luxion serves various industries, including media, manufacturing, gaming, architecture, and healthcare, and is recognized for its significant market share in North America''s 3D rendering sector.', 'The company is a licensed sponsor.', 4, 15, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/246689a1-0891-43d7-a186-9188e046bff2.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-17T00:00:00+00:00', '246689a1-0891-43d7-a186-9188e046bff2') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('MNC', 'MNC', 'https://www.mnc.co.uk', 'https://www.linkedin.com/company/mnc-ltd', 'MNC is a UK-based, independent media agency with 30 years of experience focused on building challenger brands. Located in London, MNC offers a range of media services, including media strategy and planning, above-the-line advertising, data and analytics, and agency matchmaking through the MNC Club. The agency emphasizes long-term partnerships, with an average client engagement of over nine years, and has recently expanded its ventures arm by acquiring Grwth.

MNC Ventures invests in Seed and Series A consumer brands with sustainable business models, promoting innovative approaches in the venture space. The agency has achieved significant sales growth for its clients, delivering over £1 billion in sales, showcasing its impact on long-term growth. MNC has collaborated with various notable brands, including Trivago, Wayfair, and Unilever, leveraging the expertise of its team, which includes experienced founders and agency leaders.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/ecc0204d-d7cf-45ba-8a47-2aeedec3fe48.png', TRUE, 'Very large company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', 'ecc0204d-d7cf-45ba-8a47-2aeedec3fe48') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Magnisol', 'MAGNISOL LIMITED', 'https://www.magnisol.com', 'https://www.linkedin.com/company/magnisol', 'Magnisol is an Australian-based boutique IT services and consulting firm that specializes in Human Capital Management (HCM) solutions, primarily using the Dayforce platform. The company operates globally, with a strong presence in Australia, New Zealand, Southeast Asia, Europe, South Africa, and the Americas. Founded in 2017 and headquartered in Brisbane, Queensland, Magnisol employs around 60-67 people and reported annual revenue of approximately $1 million in 2025.

The firm offers comprehensive HCM solutions, including system implementation, integration services, managed services, post-implementation support, and consulting. Magnisol focuses on simplifying HR, payroll, and workforce management processes through its expertise. It serves clients in various sectors, including hospitality and IT, and has established itself as a leading Dayforce partner. In November 2024, Magnisol announced a strategic acquisition of an equity interest in Dulili, enhancing its position in the Asia-Pacific market and expanding its service offerings.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/86cffdd1-54e2-46dc-9cf9-c8503bf4749e.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', '86cffdd1-54e2-46dc-9cf9-c8503bf4749e') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('MarFishEco Fisheries Consultants', 'MARFISHECO LTD', 'https://www.marfisheco.com', 'https://www.linkedin.com/company/marfisheco', 'MarFishEco Fisheries Consultants Ltd, also known as MarFishEco Ltd or MFE, is a network of experienced fishery professionals based in Edinburgh, Scotland, with additional offices in Portland, Oregon. Established in July 2020, the company operates globally, providing expert advice and support for sustainable and profitable fisheries in over 25–30 countries.

The company offers a range of tailored services, including the formulation of sustainability solutions, fisheries certification, and stakeholder engagement. MarFishEco is known for its objective insights in fisheries economics, ecology, social sciences, and policy. Their team includes notable experts like Morgan Lord and Andrew F. Johnson, who contribute to various reports and reviews, such as those for the Commonwealth Secretariat and the Marine Stewardship Council. These outputs address critical issues in fisheries, including technology, governance, and sustainability standards.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/236fb468-1480-4447-b038-716a8d26f425.png', TRUE, 'Very small company', NULL, NULL, TRUE, '2026-03-19T00:00:00+00:00', '236fb468-1480-4447-b038-716a8d26f425') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('MeVitae', 'Oxiway Limited t/a MeVitae', 'https://www.mevitae.com', 'https://www.linkedin.com/company/mevitae', 'MeVitae is a UK-based human resources software company located in Oxford. It specializes in AI-powered workforce solutions that focus on promoting fairness and eliminating bias in recruitment. Founded by CEO Riham Satti, who has a background in neuroscience and engineering, MeVitae aims to foster diversity, equity, and inclusion in hiring practices. The company is backed by investors and has raised under $5 million in funding.

MeVitae offers a range of AI-driven tools designed for anonymized recruiting and HR optimization. These include features for redacting personal identifiers from applications, high-accuracy processing of candidate data, and real-time insights for data-driven HR decisions. Their solutions are scalable for large organizations and integrate with over 20 HR platforms. MeVitae emphasizes ethical AI practices and aims to create successful workplaces built on trust, with a commitment to reducing turnover and boosting productivity for its clients.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/a703cfb6-192f-40da-9154-1dab7a83320d.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-09T00:00:00+00:00', 'a703cfb6-192f-40da-9154-1dab7a83320d') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Mermaid Subsea Services', 'Mermaid Subsea Services (UK) Ltd', 'https://www.mermaidsubsea.co.uk', 'https://www.linkedin.com/company/mermaid-subsea-services-uk', 'Mermaid Subsea Services (UK) Limited is a subsidiary of the Mermaid Group, focused on providing subsea solutions for the offshore energy sector, including oil and gas, decommissioning, and offshore wind. Established in February 2020 and based in Westhill, Aberdeenshire, the company operates with a small team and leverages over 40 years of experience from its parent group in subsea engineering and offshore services.

The company offers a variety of subsea engineering services, such as inspection, repair, and maintenance (IRM), subsea installation engineering, and offshore decommissioning. It has achieved significant milestones in the North Sea, including record-breaking projects and well intervention services. Mermaid Subsea Services (UK) utilizes advanced technologies like remotely operated vehicles (ROVs) and autonomous underwater vehicles (AUVs) to enhance its service delivery. The company emphasizes safety, efficiency, and budget control in all its operations.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/cd2e5905-75c0-4bf3-aebb-372ee976dcf2.png', TRUE, 'Small company', NULL, NULL, FALSE, '2026-02-24T00:00:00+00:00', 'cd2e5905-75c0-4bf3-aebb-372ee976dcf2') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Mettle Studio', 'Mettle Studio Limited', 'https://mettle-studio.com', 'https://www.linkedin.com/company/mettlestudio', 'Mettle Studio Ltd. is a UK-based design and engineering studio founded in 2014. The company specializes in product and business transformation by creating digital and physical products that foster positive organizational change. With a multidisciplinary team of around 15-16 members, Mettle Studio generates approximately $4 million in annual revenue and operates as a private limited company.

The studio focuses on turning innovative ideas into exceptional products through award-winning design and expert technical delivery. They follow a "make-test-learn" approach to navigate uncertainty and complex challenges. Mettle Studio offers end-to-end support in three main areas: design, development, and product leadership. Their services include UI/UX design, web and mobile development, cloud architecture, and digital transformation. The studio has worked on notable projects such as Thyia, Mott MacDonald Carbon Portal, and Phillips Auction House, collaborating with both major global brands and startups.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/1553c3c0-35ce-444b-8e0f-2d3ba1a0448d.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', '1553c3c0-35ce-444b-8e0f-2d3ba1a0448d') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Mobility Cyber Labs', 'Mobility Cyber Labs Ltd', 'https://www.mobilitycyberlabs.com', 'https://www.linkedin.com/company/mobility-cyberlabs', 'A team of hands-on automotive cybersecurity experts, delivering design, testing and benchmarking consulting to secure the future of mobility.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/6a3b8913-4cbb-4dec-bf63-270dd892f3cc.png', TRUE, 'Very small company', NULL, NULL, TRUE, '2026-03-18T00:00:00+00:00', '6a3b8913-4cbb-4dec-bf63-270dd892f3cc') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Molteni Group', 'MOLTENI GROUP UK LIMITED', 'https://moletenigroup.com', 'https://www.linkedin.com/company/molteniandc', 'Molteni&C is a family-owned Italian furniture design and manufacturing company, established in 1934 by Angelo Molteni in Giussano. The company has grown from a small artisan workshop into a globally recognized design leader, maintaining 100% family ownership and producing all its products in Italy.Molteni&C offers a diverse range of products, including contemporary residential furniture, high-quality kitchen furnishings through its Dada brand, and architectural partitions and office solutions via its subsidiary brands UniFor and Citterio. The company also has a Contract Division that handles high-profile commercial projects for luxury brands and provides custom fitout services. Known for its modular systems and refined craftsmanship, Molteni&C emphasizes simplicity and functionality in its designs.The company values Italian craftsmanship, quality, and sustainability, and it has established the Molteni Museum to showcase its design heritage. Molteni&C has collaborated with renowned designers and completed significant international projects, reinforcing its position as a leader in the furniture industry.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/6e5520f4-240a-4106-b05f-3e5393ecaea5.png', TRUE, NULL, NULL, NULL, FALSE, '2026-03-06T00:00:00+00:00', '6e5520f4-240a-4106-b05f-3e5393ecaea5') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Moniepoint Group', 'MONIEPOINT TECHNOLOGIES UK LTD', 'https://moniepoint.com', 'https://www.linkedin.com/company/moniepoint-inc', 'Moniepoint Group, formerly known as TeamApt, is a prominent fintech company based in London, with offices in Lagos, Nigeria, Nairobi, Kenya, and the US. Founded in 2015 by Tosin Eniolorunda and Felix Ike, Moniepoint has established itself as Africa''s fastest-growing financial ecosystem, serving over 10 million businesses and individuals across the continent.

The company operates an all-in-one digital financial platform that offers a range of services, including payments, banking, credit, and business management tools. Moniepoint processes between $17-22 billion monthly in transactions, making it Nigeria''s largest merchant acquirer. Its offerings include POS infrastructure, digital wallets, business banking apps, and working capital loans. Moniepoint also focuses on financial inclusion for micro, small, and medium enterprises (MSMEs) and has expanded its services internationally, including remittance solutions for the UK African diaspora. The company has achieved significant growth, with a recent valuation as a unicorn and recognition as Africa''s second-fastest-growing company by the Financial Times in 2023.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/3255b6ef-8fa2-4282-b4f0-000292466bb0.png', TRUE, 'Very large company', NULL, NULL, FALSE, '2026-03-04T00:00:00+00:00', '3255b6ef-8fa2-4282-b4f0-000292466bb0') ON CONFLICT DO NOTHING;
