INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Newtech Intelligent Automation', 'newtech intelligent automation ltd', 'https://newtech-ltd.co.uk', 'https://www.linkedin.com/company/newtech-ltd', 'Newtech Intelligent Automation Limited is a private limited company based in Sharnbrook, Bedford, UK. Established in 1984, it has over 41 years of experience in the industry and remains active as of January 2026. The company specializes in the design and manufacture of industrial ultrasonic slicing, cutting, portioning, and handling machines, focusing on food production automation.

As a leading manufacturer in its field, Newtech emphasizes safety, compliance, and innovation in its automated ultrasonic cutting and portioning solutions, which often include robotic handling features. The company operates as a micro-sized enterprise, employing around 14 people and maintaining a strong financial position with total assets of £2.06 million as of March 2024. Key leadership includes Managing Director Richard Martin Smith and Directors Edwin John Richard Canvin and Stephen Anthony Rawlinson.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c0e20857-b96e-4272-9cf5-3a67aa43d8b4.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-16T00:00:00+00:00', 'c0e20857-b96e-4272-9cf5-3a67aa43d8b4') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Nook Architecture & Design', 'Nook Architecture and Design Limited', 'https://nookarchitecture.co.uk', 'https://www.linkedin.com/company/nook-architecture-design-ltd', 'Nook Architecture and Design is a Leeds based architecture and design studio founded by Martin Cook and Chris Newbold in 2023. With an emphasis on design-led thinking, Nook Architecture and Design provide innovative and thought provoking contemporary architecture.

The work of the practice spans many sectors and scales, ranging from residential refurbishments and extensions, to new build homes, master planning and larger commercial projects.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/c4a9a7b5-9f7f-4826-8748-f2239cd2bc25.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', 'c4a9a7b5-9f7f-4826-8748-f2239cd2bc25') ON CONFLICT DO NOTHING;
