INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('OpenSpace', 'Open Space Labs UK, Limited', 'https://www.openspace.ai', 'https://www.linkedin.com/company/openspace.ai', 'OpenSpace is a construction technology company founded in 2017 that specializes in using computer vision and AI to convert jobsite data into actionable intelligence for builders. With over 190 employees, OpenSpace serves 371,000 users across 129 countries. The company has captured more than 52 billion square feet of construction data and processes over 1 billion images from active projects worldwide.The core offering is the Visual Intelligence Platform, which includes several integrated products such as OpenSpace Capture for documenting jobsites, OpenSpace BIM+ for integrating reality capture data with Building Information Modeling, and OpenSpace Field for real-time intelligence workflows. The platform enhances coordination between field and office teams, streamlining workflows and improving decision-making. OpenSpace has also seen significant growth, with revenues increasing over 20 times since receiving investment in 2020, and has expanded its reach to over 93 countries.', 'The company is a licensed sponsor.', 4, 1, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/f650877f-f7bc-4823-8edc-01246c1cd816.png', TRUE, NULL, 0, NULL, FALSE, '2022-09-29T00:00:00+00:00', 'f650877f-f7bc-4823-8edc-01246c1cd816') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('P/E Investments', 'P/E Investments UK Associates Ltd.', 'https://www.peinvestments.com', 'https://www.linkedin.com/company/p-e-investments-llc', 'Our team of professionals offers extensive experience in portfolio management, asset allocation, market analysis, and risk management. With a focus on currency and global macro strategies, we manage assets for institutional and qualified individual investors, worldwide.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/594ce796-7a29-48a9-8d2b-6732265c1643.png', TRUE, 'Medium-sized company', NULL, NULL, FALSE, '2026-02-27T00:00:00+00:00', '594ce796-7a29-48a9-8d2b-6732265c1643') ON CONFLICT DO NOTHING;
