INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Valkyrie Industries', 'Valkyrie Industries', 'https://www.valkyrie-vr.com', 'https://www.linkedin.com/company/valkyrieindustries', 'Valkyrie Industries is a UK-based technology company founded in 2017, focusing on patented haptic wearables that combine neuromuscular electrical muscle stimulation (NMES/EMS) with extended reality (XR) and virtual reality (VR). The company aims to enhance muscle training, recovery, and performance while providing immersive experiences. Headquartered in Ingatestone, Essex, Valkyrie Industries has received funding, including a significant investment from ASICS Ventures Corporation, to support its growth and market expansion.

The company''s flagship product, the eir bands, is a lightweight EMS/NMES-powered wearable designed for upper arm muscles. It delivers resistance sensations and real-time muscle stimulation in VR/XR environments. Valkyrie Industries also offers the v-health platform, which provides interactive XR therapy for muscle recovery and functional therapy. Their technology serves various sectors, including healthcare, fitness, wellness, engineering, and creative industries, emphasizing human-centered design and adaptive haptics.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/566c3e50-5568-4900-ba03-095bec914ca0.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '566c3e50-5568-4900-ba03-095bec914ca0') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('Vegware', 'Vegware Ltd', 'https://www.vegware.com/', 'https://www.linkedin.com/company/vegware', 'Vegware is a leading provider of compostable foodservice packaging, based in Edinburgh, Scotland. Founded in 2006, the company operates in over 70 countries, including the U.K., EU, United States, Middle East, South America, and the Caribbean. Vegware offers a variety of plant-based products designed for commercial composting, such as cups, cutlery, tableware, and takeout packaging. Their products are recognized for quality, performance, and design.

In addition to manufacturing, Vegware provides waste management and composting programs. They partner with regional waste sectors in the U.K. and operate "Close the Loop," a composting collection service. In the United States, they offer advice on composting options through their Product and Zero Waste Specialists. Vegware has been acknowledged as Scotland''s fastest growing exporter and continues to expand its reach in the sustainable packaging market.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/d8fdcc1b-1b6a-40b7-80dd-38ff72860b6c.png', TRUE, 'Medium-sized company', NULL, NULL, TRUE, '2026-03-10T00:00:00+00:00', 'd8fdcc1b-1b6a-40b7-80dd-38ff72860b6c') ON CONFLICT DO NOTHING;
