INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('aisy', 'Aisy Ltd', 'https://aisy.ai', 'https://www.linkedin.com/company/aisy', 'Aisy''s AI-native threat model intelligence platform turns overwhelming vulnerability data into clear, attacker-driven priorities that free up your team to focus on real risk.', 'The company is a licensed sponsor.', 4, 0, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/65df7b3e-9ba0-49aa-bf25-355555c1e3ff.png', TRUE, 'Very small company', NULL, NULL, FALSE, '2026-02-23T00:00:00+00:00', '65df7b3e-9ba0-49aa-bf25-355555c1e3ff') ON CONFLICT DO NOTHING;
INSERT INTO companies (trading_name, companies_house_name, url, url_linkedin, description, policy, open_to_sponsorship, active_jobs_count, url_favicon, licensed_sponsor, estimated_num_employees_label, cos_used_count_2025, sponsored_employees_count, show_recently_added_badge, added_to_register, favicon_id) VALUES ('rePLANET', 'REPLANET LIMITED', 'https://www.replanet.org.uk', 'https://www.linkedin.com/company/replanetco', 'rePLANET is a purpose-driven company focused on attracting private sector finance to restore and protect nature globally. Established in 2020 as a joint venture, it evolved from Operation Wallacea, a leader in biodiversity research. The company aims to enhance the financial viability of ecological restoration, particularly through mangrove reforestation, while ensuring that 60% of project income benefits local stakeholders.

rePLANET develops high-quality nature-based solutions and offers consultancy services to corporates and landowners, guiding them in their natural capital journey. The company specializes in biodiversity monitoring and quantification, employing expert ecologists and remote sensing specialists to create effective monitoring strategies. Additionally, rePLANET develops carbon and biodiversity credits, helping clients generate validated Nature Positive Claims. Their innovative approach combines ecosystem restoration with agricultural improvements, emphasizing local livelihoods and food security.', 'The company is a licensed sponsor.', 4, 2, 'https://xhtezeeaeqjfdhrkltox.supabase.co/storage/v1/object/public/company_icons/73e06f7d-423f-4324-afba-a70d0371d295.png', TRUE, 'Small company', NULL, NULL, TRUE, '2026-03-12T00:00:00+00:00', '73e06f7d-423f-4324-afba-a70d0371d295') ON CONFLICT DO NOTHING;
